<?php
require_once __DIR__ . '/../app/bootstrap.php';
$admin = require_role('admin');
$summary = analytics_summary();
$recentVisits = db_all('SELECT page_url, page_title, referrer, created_at FROM website_visits ORDER BY created_at DESC LIMIT 80');
$topPages = db_all('SELECT page_url, COUNT(*) AS visits, COUNT(DISTINCT visitor_key) AS unique_visitors FROM website_visits GROUP BY page_url ORDER BY visits DESC LIMIT 20');
$daily = db_all('SELECT DATE(created_at) AS day, COUNT(*) AS visits, COUNT(DISTINCT visitor_key) AS unique_visitors FROM website_visits GROUP BY DATE(created_at) ORDER BY day DESC LIMIT 14');
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Website Analytics</title><style>body{margin:0;background:#f8faff;font-family:Inter,Arial,sans-serif;color:#111827}.top{background:#07101e;color:#fff;padding:22px 0}.wrap{width:min(1180px,calc(100% - 40px));margin:auto}.top .wrap{display:flex;justify-content:space-between}.nav{display:flex;gap:18px}a{color:inherit;text-decoration:none}.hero{padding:42px 0}.kicker{color:#2f68ff;font-size:11px;font-weight:900;letter-spacing:.18em;text-transform:uppercase}h1{font-size:42px;letter-spacing:-.055em;margin:10px 0}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:22px}.card,.panel{background:#fff;border:1px solid #edf0f6;border-radius:16px;padding:22px;box-shadow:0 18px 48px rgba(18,30,57,.055)}.card span{display:block;color:#667085;font-size:12px;font-weight:800;text-transform:uppercase}.card strong{display:block;font-size:38px;letter-spacing:-.055em;margin-top:8px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}table{width:100%;border-collapse:collapse}td,th{padding:11px;border-bottom:1px solid #edf0f6;text-align:left;font-size:13px;vertical-align:top}th{font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:#667085}.url{max-width:420px;word-break:break-word;color:#2f68ff}@media(max-width:920px){.cards,.grid{grid-template-columns:1fr}.top .wrap{display:grid;gap:12px}}</style></head><body><header class="top"><div class="wrap"><strong>David Evans CRM</strong><nav class="nav"><a href="/admin/dashboard.php">Requests</a><a href="/admin/chat.php">Chats</a><a href="/admin/account.php">Account</a><a href="/admin/logout.php">Logout</a></nav></div></header><main class="wrap"><section class="hero"><div class="kicker">Analytics Dashboard</div><h1>Website visits and chat activity</h1><p>Track visits, unique visitors, open chats, and project request activity.</p></section><section class="cards"><div class="card"><span>Visits Today</span><strong><?= (int)$summary['visits_today'] ?></strong></div><div class="card"><span>Unique Today</span><strong><?= (int)$summary['unique_today'] ?></strong></div><div class="card"><span>Open Chats</span><strong><?= (int)$summary['chats_open'] ?></strong></div><div class="card"><span>New Requests</span><strong><?= (int)$summary['new_requests'] ?></strong></div></section><section class="grid"><div class="panel"><h2>Top pages</h2><table><thead><tr><th>Page</th><th>Visits</th><th>Unique</th></tr></thead><tbody><?php foreach ($topPages as $row): ?><tr><td class="url"><?= e($row['page_url']) ?></td><td><?= (int)$row['visits'] ?></td><td><?= (int)$row['unique_visitors'] ?></td></tr><?php endforeach; ?></tbody></table></div><div class="panel"><h2>Last 14 days</h2><table><thead><tr><th>Day</th><th>Visits</th><th>Unique</th></tr></thead><tbody><?php foreach ($daily as $row): ?><tr><td><?= e($row['day']) ?></td><td><?= (int)$row['visits'] ?></td><td><?= (int)$row['unique_visitors'] ?></td></tr><?php endforeach; ?></tbody></table></div></section><section class="panel" style="margin-top:18px"><h2>Recent visits</h2><table><thead><tr><th>Page</th><th>Referrer</th><th>Time</th></tr></thead><tbody><?php foreach ($recentVisits as $row): ?><tr><td class="url"><?= e($row['page_title'] ?: $row['page_url']) ?><br><small><?= e($row['page_url']) ?></small></td><td><?= e($row['referrer'] ?: 'Direct') ?></td><td><?= e($row['created_at']) ?></td></tr><?php endforeach; ?></tbody></table></section></main></body></html>
